CREATE TABLE artifacts(id TEXT PRIMARY KEY,owner TEXT NOT NULL,source TEXT NOT NULL, schema_version INTEGER NOT NULL DEFAULT 1);
CREATE TABLE discrepancies(id INTEGER PRIMARY KEY,operation TEXT NOT NULL UNIQUE,actor TEXT NOT NULL,artifact_id TEXT NOT NULL,source TEXT NOT NULL,ancestry TEXT,reason TEXT NOT NULL,status TEXT NOT NULL,operation_result_id TEXT NOT NULL,expected_hash TEXT,observed_hash TEXT,context TEXT NOT NULL, expected_identity TEXT, observed_identity TEXT, schema_version INTEGER NOT NULL DEFAULT 1, proposed_hash TEXT, observed_owner TEXT, observed_source TEXT, observed_ancestry TEXT);
CREATE TABLE lineage(operation_id TEXT PRIMARY KEY,version_id TEXT NOT NULL,parent_version_id TEXT, schema_version INTEGER NOT NULL DEFAULT 1,FOREIGN KEY(operation_id) REFERENCES operations(id),FOREIGN KEY(version_id) REFERENCES versions(id),FOREIGN KEY(parent_version_id) REFERENCES versions(id));
CREATE TABLE operations(id TEXT PRIMARY KEY,fingerprint TEXT NOT NULL,result TEXT NOT NULL,version_id TEXT,lineage TEXT,rejection_code TEXT,schema_version INTEGER NOT NULL,FOREIGN KEY(version_id) REFERENCES versions(id));
CREATE TABLE schema_metadata(key TEXT PRIMARY KEY,value INTEGER NOT NULL);
INSERT INTO schema_metadata VALUES('schema_version',1),('migration_lineage',1);
CREATE TABLE versions(id TEXT PRIMARY KEY,artifact_id TEXT NOT NULL,hash TEXT NOT NULL,canonical TEXT NOT NULL,ancestry TEXT,operation TEXT NOT NULL UNIQUE,actor TEXT NOT NULL,source TEXT NOT NULL,observed_identity TEXT,expected_hash TEXT,schema_version INTEGER NOT NULL, source_schema_version INTEGER NOT NULL DEFAULT 1, source_lineage TEXT NOT NULL DEFAULT 'native',FOREIGN KEY(artifact_id) REFERENCES artifacts(id),FOREIGN KEY(ancestry) REFERENCES versions(id));
CREATE INDEX versions_artifact ON versions(artifact_id);
CREATE TRIGGER immutable_discrepancies_delete BEFORE DELETE ON discrepancies BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_discrepancies_update BEFORE UPDATE ON discrepancies BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_lineage_delete BEFORE DELETE ON lineage BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_lineage_update BEFORE UPDATE ON lineage BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_operations_delete BEFORE DELETE ON operations BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_operations_update BEFORE UPDATE ON operations BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_versions_delete BEFORE DELETE ON versions BEGIN SELECT RAISE(ABORT,'immutable'); END;
CREATE TRIGGER immutable_versions_update BEFORE UPDATE ON versions BEGIN SELECT RAISE(ABORT,'immutable'); END;
